var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……스승님.","JPN":"……師匠。","ENG":"Master...","TWN":"……師父。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭔가 착각하신 모양인데 여긴 보육원이 아닙니다.","JPN":"何か勘違いされているようですが、ここは保育園ではありません。","ENG":"Just so you know, this is not an orphanage.","TWN":"是不是有什麼誤會？這裡不是幼稚園。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 어쩌자고 저런 어린애를 데리고 오신 거죠?","JPN":"いったい何のつもりであんな子どもを連れてきたんですか？","ENG":"Why did you bring the kid here?","TWN":"您把那麼小的孩子帶來這裡是想做什麼呢？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"워치를 가지고 있고 카운터 적성도 높아.","JPN":"ウォッチを持ち、カウンター適性も高い。","ENG":"He's got a Watch and shows promising signs of becoming a Counter.","TWN":"他有能量環，制裁者適能也很高。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"항상 회사에 인력이 부족하다고 노래를 부르지 않았나?","JPN":"いつも会社に人手が足りないと訴えていなかったか？","ENG":"You were always complaining that you needed more people, weren't you?","TWN":"你不是一天到晚在哼人力短缺之歌嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말씀드리지만 저건 <color=#ffd34c>어린애</color>입니다.","JPN":"もう一度申し上げますが、あれは<color=#ffd34c>小さな子ども</color>ですよ。","ENG":"In case you missed this little detail, he's <color=#ffd34c>a child</color>.","TWN":"請容我再次提醒您，他只是個<color=#ffd34c>孩子</color>啊！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 부족하다고 했던 인력은 작전에 투입할 수 있는 현장직이고요.","JPN":"私が足りないと言った人手は作戦に投入できる現場職です。","ENG":"The people I need are active field agents I can send on actual operations right away.","TWN":"我缺的是可以直接投入作戰的人力。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 저런 꼬마를 현장에 데리고 다닐 생각이십니까?","JPN":"まさかあんな子どもを現場に連れて行くつもりですか？","ENG":"You're not thinking of taking the kid around with you, are you?","TWN":"您該不會是想帶著那麼丁點大的孩子衝鋒陷陣吧？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……네가 펜릴 전대에 들어왔을 때도 그다지 나이가 많은 건 아니었는데.","JPN":"……お前がフェンリル戦隊に入った当時と、そんなに歳は変わらないぞ。","ENG":"…You weren't much older than him when you joined Fenrir Division.","TWN":"……你加入芬里爾戰隊戰隊時也沒比他大多少好嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 전 천재였으니까요.","JPN":"それは私が天才だったからです。","ENG":"Well, I was a genius.","TWN":"那是因為我是天才啊。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 아이가 그때 제 실력의 반만큼이라도 따라온다면 반대하지 않겠습니다.","JPN":"あの子が当時の私の半分程度の実力もあるなら反対はしません。","ENG":"If this kid's at least half as good as I was back then, I won't object.","TWN":"這個孩子的能力如果有我當初的一半，那我就立刻閉嘴。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런가요?","JPN":"どうですか？","ENG":"Is he though?","TWN":"他有嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건…… 당장은 힘들겠군.","JPN":"それは……今すぐは難しそうだな。","ENG":"That… might be difficult to achieve, for now.","TWN":"這個……我無法保證。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래도 사람이 인정이라는 게 있는데 사정을 좀 봐 주면……","JPN":"人情という言葉があるだろう、今回は大目に見てやって……","ENG":"But can't you find the heart to be more flexible?","TWN":"話雖如此，人家說情理法，用人情的角度來看……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"기준을 조금 낮춰 볼 수는 없겠나?","JPN":"基準を少し下げることはできないか？","ENG":"How about you lower your bar a little?","TWN":"就不能稍微降低標準嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님 입에서 인정이라는 말이 나오다니 참 놀랍네요.","JPN":"師匠の口から人情という言葉が出るとは、本当に驚きですね。","ENG":"I can't believe you just mentioned anything about the heart.","TWN":"我竟然會從師父口裡聽到人情這兩個字。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 왜 안대를 차게 됐나 떠올린 다음에 다시 말씀해 보시죠.","JPN":"私がなぜ眼帯をするようになったのか、思い出してからもう一度話していただけませんか？","ENG":"Let's table this discussion, until you've considered why I'm wearing this eye patch in the first place.","TWN":"在跟我談人情之前，要先回想一下我為什麼會戴眼罩嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"크흠…….","JPN":"こほん……","ENG":"Ahem…","TWN":"嗯……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};